slides.codeSnippet:
// TS knows this is a string, no annotation needed
let username = "John";

// TS knows this is a boolean
let isActive = true;

// Good: Inference handles it
let age = 30;

// Bad: Defaults to 'any'
let name;
name = "Alice";

// Good: Explicitly telling TS what it will be
let city: string;
city = "Tokyo";
